INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (53, 133327, 7, 136, '爱情是无私的', '敬爱的各位老师各位同学，大家晚上好！经过一番激烈的唇枪舌剑，我们此次的辩论大赛已经接近尾声，在这最后时刻，由我，四号辩手，谨代表我方全体选手，做最后总结性发言，再一次陈述我方观点。我方认为，爱情是无私的，也许你会说，爱情是自私的，情人的眼里容不下一粒沙子；也许你会说，爱情是专一的，恋爱中的双方具有强烈的占有欲和排他性，而且关于这一观点，对方辩友已经做了精彩的解答。然而我方坚持认为，爱情是无私的！那种认为爱情是自私的只是当代社会一些小男小女的小情小感，不是真正的爱情。真正的爱情是一种责任，一种付出，一种百分之百的付出，百分之百的不求回报。但百分之百的不求回报并不带表着没有回报。在恋爱中，你所得到的回报是一个顺其自然的过程。因为这是你所得到的，而不是你所索取的。这两者有质的区别。你的无私的付出，换回对方的热诚回报，而对方的这种热诚回报，相对于他自己来说，做为恋爱中的一方，真实一中无私的付出。你的付出和他的付出，你的无私和他的无私，成就了一段美好的姻缘。爱情是什么？不是空中楼阁，不是空心菜，而是实实在在的两个人两颗心之间的激烈的碰撞和结合，是百分之百的付出并无所求。如果你不具备付出的精神，而一味想着回报，你就不具备爱一个人的资格，你就不配拥有真正的爱情！真正的爱情是无私的，超越年龄，超越性别，超越时空，超越小我铸就大我，超越个人的小男小女的小情小感。从而达到一种至善至美的完美的境界。而所谓的爱情自私论，只是因为现代社会中的某个人，某些人，他们人性的自私，他们只想着对方的回报，而不想自己能为对方付出多少，他们人性的自私，而说我们伟大的无私的爱情是自私的。正是这种自私人的越来越多，越发显得无私爱情的难能可贵，爱情本质上是无私的。在此，引用一句话，做为我此次发言的结尾；愈想占有，愈容易失去，爱是尽量占有和尽量避免失去之间的平衡！
<br>最后，祝愿在场的各位都能够发扬我们伟大的无私的人性，早日找到或者已经能够找到属于你自己的真正的伟大的无私的爱情，祝愿天下有情人终成眷属，只羡鸳鸯不羡仙！谢谢！！！
<br>（呵呵：）最佳辩手的陈词哈哈哈哈哈哈哈哈…………………………………………………………………………）', '敬爱的各位老师各位同学，大家晚上好！经过一番激烈的唇枪舌剑，我们此次的辩论大赛已经接近尾声，在这最后时刻，由我，四号辩手，谨代表我方全体选手，做最后总结性发言，再一次陈述我方观点。我方认为，爱情是无私的，也许你会说，爱情是自私的，情人的眼里容不下一粒沙子；也许你会说，爱情是专一的，恋爱中的双方具有强烈的占有欲和排他性，而且关于这一观点，对方辩友已经做了精彩的解答。然而我方坚持认为，爱情是无私的！那种认为爱情是自私的只是当代社会一些小男小女的小情小感，不是真正的爱情。真正的爱情是一种责任，一种付出，一种百分之百的付出，百分之百的不求回报。但百分之百的不求回报并不带表着没有回报。在恋爱中，你所得到的回报是一个顺其自然的过程。因为这是你所得到的，而不是你所索取的。这两者有质的区别。你的无私的付出，换回对方的热诚回报，而对方的这种热诚回报，相对于他自己来说，做为恋爱中的一方，真实一中无私的付出。你的付出和他的付出，你的无私和他的无私，成就了一段美好的姻缘。爱情是什么？不是空中楼阁，不是空心菜，而是实实在在的两个人两颗心之间的激烈的碰撞和结合，是百分之百的付出并无所求。如果你不具备付出的精神，而一味想着回报，你就不具备爱一个人的资格，你就不配拥有真正的爱情！真正的爱情是无私的，超越年龄，超越性别，超越时空，超越小我铸就大我，超越个人的小男小女的小情小感。从而达到一种至善至美的完美的境界。而所谓的爱情自私论，只是因为现代社会中的某个人，某些人，他们人性的自私，他们只想着对方的回报，而不想自己能为对方付出多少，他们人性的自私，而说我们伟大的无私的爱情是自私的。正是这种自私人的越来越多，越发显得无私爱情的难能可贵，爱情本质上是无私的。在此，引用一句话，做为我此次发言的结尾；愈想占有，愈容易失去，爱是尽量占有和尽量避免失去之间的平衡！

最后，祝愿在场的各位都能够发扬我们伟大的无私的人性，早日找到或者已经能够找到属于你自己的真正的伟大的无私的爱情，祝愿天下有情人终成眷属，只羡鸳鸯不羡仙！谢谢！！！

